{
  "name": "Apartamento Centro Madrid",
  "description": "Piso de 90m2 — testing AI interior design"
}

{
  "mode": "style_redesign",
  "preset": "modern_mediterranean",
  "provider": "openai",
  "instructions": "Furnish this space with warm Mediterranean style. Use terracotta tones, natural wood, and light fabrics. Keep the exact architecture unchanged."
}

{
  "mode": "style_redesign",
  "preset": "premium_contemporary",
  "provider": "openai",
  "instructions": "Redesign with sleek contemporary furniture, neutral palette, elegant lighting. Preserve all walls, floor, ceiling, and windows exactly."
}

{
  "mode": "style_redesign",
  "preset": "urban_contemporary",
  "provider": "openai",
  "instructions": "Urban loft style with industrial elements, exposed materials, dark metal accents. Keep architecture intact."
}

{
  "mode": "commercial_enhancement",
  "provider": "openai",
  "instructions": "Make this space look professional and attractive for real estate listings. Improve lighting, staging, and overall appeal."
}

{
  "mode": "functional_variant",
  "preset": "living_tv_wall",
  "provider": "openai",
  "instructions": "Convert this space into a modern living room with a sleek TV wall, media console, and comfortable seating. Keep architecture unchanged."
}

{
  "mode": "functional_variant",
  "preset": "dining_room",
  "provider": "openai",
  "instructions": "Transform into an elegant dining room with a central table for 6, stylish chairs, and a chandelier. Preserve all architecture."
}

{
  "mode": "functional_variant",
  "preset": "home_office_lounge",
  "provider": "openai",
  "instructions": "Create a comfortable home office with a desk, ergonomic chair, bookshelves, and a reading nook. Keep walls and floor unchanged."
}

{
  "mode": "localized_edit",
  "preset": "localized_wall_art",
  "provider": "openai",
  "instructions": "Replace the wall art with large colorful abstract paintings. Keep everything else exactly the same."
}

{
  "mode": "localized_edit",
  "preset": "localized_sofa",
  "provider": "openai",
  "instructions": "Replace the sofa with a large L-shaped velvet sofa in deep green. Keep everything else unchanged."
}

{
  "mode": "localized_edit",
  "provider": "openai",
  "instructions": "Replace the pillows on the bed with cute teddy bears. Keep absolutely everything else the same — same bed, same walls, same floor, same lighting."
}

{
  "mode": "localized_edit",
  "provider": "openai",
  "instructions": "Replace the ceiling fan with an elegant large French crystal chandelier. Keep everything else exactly as it is."
}
